import { color } from "framer-motion";
import { useMouseMove, animate, useValue } from "react-ui-animate"
import './Bubbles.css';

function BubbleCursor() {

    // const mx = useValue(0)
    // const my = useValue(0)

    var lastX = 0
    var lastY = 0
    var dist_thresh = 8
    // const angle = useValue(0)
    // const xAcc = useValue(0)
    // const yAcc = useValue(0)
    // const iAc = 7 // initial accel
    // var xAccPrev = [iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc]
    // var yAccPrev = [iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc]
    // var angPrev = [0,0,0,0,0,0]
    // const flip = useValue("100%")
    // const maxAcc = 5
    // const minDist = 30

    var T_RATE = 4
    var t = T_RATE

    // const WOBBLE = 50
    // var FLOATATE = .3v


    const average = array => array.reduce((a, b) => a + b) / array.length;

    function createBubble (mx, my) {
        const container = document.getElementById("bubblesContainer")
        const newBubble = document.createElement('span')

        var size = Math.random() * 80 + 20;
        newBubble.style.width = size + "px";
        newBubble.style.height = size + "px";


        var posX = mx;
        var posY = my;
        newBubble.style.left = posX +  "px"
        newBubble.style.top = posY +  "px"

        container.appendChild(newBubble)
        console.log("====== added bubble at ",mx," , ",my)
        setTimeout(() => {
            newBubble.remove()
        }, 400+Math.random()*20000 / size**.5)
    }

  function quadratic(x1, y1, x2, y2 ) {
    var dx = x1 - x2
    var dy = y1 - y2
    var sum = dx**2 + dy**2
    var root = sum**.5
    return root
  }

  useMouseMove(({mouseX, mouseY}) => {
        t += 1;
        console.log(t)

        if (t > T_RATE) {
            // createBubble(mouseX, mouseY)
            var quad_dist = quadratic(lastX, lastY, mouseX, mouseY)
            if (quad_dist > dist_thresh) {
                createBubble(mouseX, mouseY)
            }
            lastX = mouseX
            lastY = mouseY
            t = 0
        }

  });

  return (
    <animate.div
    id="bubblesContainer"
    style={{
        width: "100vw",
        height: "100vh",
        position: "fixed",
        top: 0,
        left: 0,
    }}
  >
  </animate.div>


  )
}

export default BubbleCursor;
